CREATE TABLE IF NOT EXISTS IF NOT EXISTS "message_logs" (
    msg_id INTEGER, 
    chat_id INTEGER, 
    topic_id INTEGER, 
    user_id INTEGER,
    text TEXT, 
    timestamp INTEGER, 
    status TEXT DEFAULT 'PENDING', 
    resolved_by TEXT, 
