INSERT OR IGNORE INTO feedback_logs VALUES(97,248,-1003768834039,1,'Already Resolved (ဖြေရှင်းပြီး)',replace('Royal ဖက်က Payment ကောက်မယ်ဆိုလို့ Customers ကို ငွေပြန်လွှဲပေးလိုက်တယ်နော်\n[Trailing Pattern]:\n- Payment ကောက်စရာ မလိုနော် ညီမ\n- Customer ငွေလွှဲထားပြီးပြီနော် အစ်မ Payment ကောက်စရာ မလိုဘူးလို့ ရေးပေးထားပါတယ် 🥰\n- Payment ကောက်စရာ မလိုလို့ ရေးပေးထားပါတယ် ညီမ','\n',char(10)),7261311241,1777275484);
