CREATE TABLE IF NOT EXISTS master_rules (
                     id INTEGER PRIMARY KEY AUTOINCREMENT,
                     rule_content TEXT,
                     chat_id INTEGER,
                     topic_id INTEGER,
                     created_at INTEGER
                   );
INSERT OR IGNORE INTO master_rules VALUES(1,'Ignore requests for specific items/services when preceded by respectful address terms (e.g., ''အမကို'')',-1003898476625,1,1777149015);
INSERT OR IGNORE INTO master_rules VALUES(2,'Do not alert on messages containing politeness markers and requests (e.g., ''လို့ရမလားရှင့်'')',-1003898476625,1,1777149015);
INSERT OR IGNORE INTO master_rules VALUES(3,'Ignore messages containing time-related requests and promises (e.g., ''ညနေလာအပ်ရင်ယူမယ်ရှင့်'')',-1003898476625,1,1777149015);
